import * as React from "react"
import Post from "../../../components/post"

type Props = {
  data: {
    post: any
    [key: string]: any
  }
  [key: string]: any
}

const onScroll = (tocLinkElements) => {
  const currentoffsetY = window.pageYOffset
  let headingFlag = false
  for(let i=tocLinkElements.length-1; i>=0; i--) {
    const heading = document.getElementById(tocLinkElements.item(i).getAttribute('href').substring(1))
    const {top} = heading.getBoundingClientRect()
    const elementTop = top + currentoffsetY
    if (currentoffsetY >= elementTop-200 && !headingFlag) {
      tocLinkElements.item(i).style.color = 'var(--theme-ui-colors-light)'
      tocLinkElements.item(i).style.backgroundColor = 'var(--theme-ui-colors-dark)'
      headingFlag = true
    } else {
      tocLinkElements.item(i).style.color = ''
      tocLinkElements.item(i).style.backgroundColor = ''
    }
  }
}

export function toFit(cb, { dismissCondition = () => false, triggerCondition = () => true }) {
  if (!cb) {
    throw Error('Invalid required arguments')
  }

  let tick = false

  return function() {
    if (tick) {
      return
    }

    tick = true
    return requestAnimationFrame(() => {
      if (dismissCondition()) {
        tick = false
        return
      }

      if (triggerCondition()) {
        tick = false
        return cb()
      }
    })
  }
}
 
