export default function MinimalBlogCorePost({ ...props }: Props) {
  React.useEffect(() => {
    const tocLinkElements = document.getElementsByClassName('toc-anchor')
    const currentoffsetY = window.pageYOffset
    for(const tocLinkElement of tocLinkElements) {
      const heading = document.getElementById(tocLinkElement.getAttribute('href').substring(1))
      const {top} = heading.getBoundingClientRect()
      tocLinkElement.addEventListener('click', e => {
        e.preventDefault()
        window.scroll({ top: top+currentoffsetY, behavior: 'smooth' })
      })
    }
    // const headings = document.querySelectorAll('h3, h4, h5, h6')
    // window.addEventListener('scroll', toFit(onScroll(toc)))
    document.addEventListener('scroll', _ => (
      onScroll(tocLinkElements)
    ))
  });
    
  return <Post {...props} />
}
